<template>
  <div>
    <nav class="navbar navbar-expand-lg navbar-light bg-light hdr">
      <router-link to="/user" class="img-router" v-if="token">
        <img src="../assets/user.png" height="64" />
        <p v-if="user">{{ user.first_name }} {{ user.last_name }}</p>
      </router-link>
      <router-link to="/login" class="img-router" v-else>
        <img src="../assets/user.png" height="64" />
        <p>Login</p>
      </router-link>
      <router-link to="/payment" class="img-router">
        <img src="../assets/payment.png" height="64" />
        <p>$ 100,000</p>
      </router-link>
      <router-link to="/dashboard" class="img-router">
        <img src="../assets/dashboard.png" height="64" />
        <p>DashBoard</p>
      </router-link>
    </nav>
  </div>
</template>

<script>
import axios from "axios";

export default {
  name: "HomeView",
  components: {
    // HelloWorld,
  },
  data() {
    return {
      token: this.getCookie("token"),
      user: null,
    };
  },
  methods: {
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
  mounted() {
    axios
      .get(`${this.host}/api/user/`, {
        headers: { Authorization: `Bearer ${this.getCookie("token")}` },
      })
      .then((user) => {
        this.user = user.data;
      });
  },
};
</script>

